require\('dotenv'\).config\({ path: '../.env' }\);
const nodemailer = require\('nodemailer'\);

const transporter = nodemailer.createTransport\({
  service: 'gmail',
  host: 'smtp.gmail.com',
  port: 587,
  secure: false,
  auth: {
    user: process.env.GMAIL_USER,
    pass: process.env.GMAIL_PASS,
  },
  tls: { rejectUnauthorized: false },
}\);

// Send a test registration email to admin
transporter.sendMail\({
  from: '\\"Salem Yogasana Festival 2026\\" <' + process.env.GMAIL_USER + '>',
  to: process.env.ADMIN_EMAIL,
  subject: 'TEST: Registration Email Test',
  html: '<h2>This is a test email to verify registration emails are working.</h2><p>If you see this, the email system is functional.</p>',
}\).then\(\(info\) => {
  console.log\('Test email sent successfully!'\);
  console.log\('MessageId:', info.messageId\);
  console.log\('Response:', info.response\);
}\).catch\(\(err\) => {
  console.error\('Test email FAILED:', err.message\);
}\);
")
